            display: inline-block;
            width: 3px;
            height: 1.8rem;
            background: #fff;
            margin-left: 4px;
            vertical-align: text-bottom;
            animation: blink 0.8s step-end infinite;
        }
        .cursor.idle {
            animation: none;
            opacity: 0;
        }
        @keyframes blink {
            50% { opacity: 0; }
        }
    </style>
</head>
<body>
    <div class="card">
        <h1>🕒 打字机时钟</h1>
        <div class="typewriter">
            <span id="text"></span><span id="cursor" class="cursor"></span>
        </div>
    </div>
    <script>
        const textEl = document.getElementById('text');
        const cursorEl = document.getElementById('cursor');
        let eventSource = null;
        let typing = false;

        function connect() {
            if (eventSource) {
                eventSource.close();
            }

            eventSource = new EventSource('/sse/time');

            eventSource.addEventListener('char', function(e) {
                typing = true;
                cursorEl.classList.remove('idle');
                textEl.textContent += e.data;
            });

            eventSource.addEventListener('done', function() {
                typing = false;
                cursorEl.classList.add('idle');
            });

            eventSource.onerror = function() {
                eventSource.close();
                setTimeout(connect, 1000);
            };
        }

        connect();
    </script>
</body>
</html>
